def check_celery(venv_path, app_name):
    def _check():
        result = subprocess.run(
            [f"{venv_path}/bin/celery", "-A", app_name, "inspect", "ping"],
            capture_output=True, text=True, timeout=10,
        )
        return "pong" in result.stdout.lower()
    return _check
